children.text:
body { font-family: sans-serif; margin: 20px; }
.test { margin: 20px 0; padding: 10px; border: 1px solid #ccc; }
img { border: 1px solid red; background: #fee; }
.label { font-weight: bold; margin-bottom: 5px; }
.size { color: #666; font-size: 12px; }

window.addEventListener('load', function() {
  for (var i = 1; i <= 8; i++) {
    var img = document.getElementById('img' + i);
    var rect = img.getBoundingClientRect();
    var cs = getComputedStyle(img);
    document.getElementById('size' + i).textContent =
      'offsetWidth=' + img.offsetWidth + ' offsetHeight=' + img.offsetHeight +
      ' | getBoundingClientRect: ' + Math.round(rect.width) + 'x' + Math.round(rect.height) +
      ' | computed: ' + cs.width + ' x ' + cs.height;
  }
});
